{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Up to the greater of 200% of the federal poverty level (FPL), 60% of the state median income (SMI), or 80% of the area median income (AMI). Exact dollar amounts vary by household size, year, and metric; contact local agency for current table as specific figures not listed in state guidance[2].",
    "asset_limits": "No asset limits mentioned in Washington-specific guidance[2].",
    "other_requirements": ["Households must be homeowners or renters (with landlord approval for renters)[2][3]", "Eligibility determined by local weatherization agency based on income thresholds[2]", "Priority often given to households with elderly members, young children, or disabilities, though not a strict requirement[3][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive energy audit by certified professional, followed by cost-effective weatherization upgrades to improve home energy efficiency, health, and safety (e.g., insulation, air sealing, heating system repairs). No fixed dollar amount or hours; services based on audit results and available funding[2].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local weatherization agency by county (phone/email listed at https://www.commerce.wa.gov/weatherization/ )[2]", "No statewide online form; apply through county-specific providers (e.g., OIC of Washington for Adams County: 509-452-7145, be.r@oicofwa.org)[2]"],
    "processing_time": "Not specified; varies by local agency[2].",
    "waitlist": "Likely due to funding limits, but not detailed; contact local agency[2].",
    "forms": ["No specific statewide form name/number; local agencies use DOE-approved processes[2]"],
    "documents": ["Proof of income for all household members", "Proof of residency/utility bills", "ID for household head", "Landlord permission if renter (exact list confirmed by local agency)[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via local subgrantees; serves all counties[2].",
    "regional_variations": "Administered by different local agencies per county with varying contact info, potential differences in wait times, capacity, and processing[2].",
    "offices_or_providers": ["County-specific list at https://www.commerce.wa.gov/weatherization/ (e.g., OIC of Washington for Adams, Community Action Partnership for Asotin)[2]"]
  },
  "official_source": "https://www.commerce.wa.gov/weatherization/",
  "gotchas": ["Must contact county-specific local agency—no central statewide application[2]", "Renters need landlord approval, which can delay or block services[2][3]", "Exact income eligibility requires local verification across 200% FPL, 60% SMI, or 80% AMI—may qualify under one even if not others[2]", "Priority for elderly/seniors but not guaranteed; funding-limited with possible waitlists[2][3]", "Not available if home in foreclosure or planned sale (general WAP rule)[1]"],
  "data_shape_notes": "Administered county-by-county through local agencies with no centralized application; eligibility uses max of three income metrics (200% FPL, 60% SMI, 80% AMI); priority tiers favor elderly and vulnerable households"
}

{
  "name": "Health Insurance Counseling and Advocacy Program (HICAP/SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; prioritizes people with limited incomes but open to all[2]",
    "asset_limits": "No asset limits or tests apply[1][2]",
    "other_requirements": ["Eligible for Medicare (age 65+ or under 65 with disabilities), soon-to-be eligible for Medicare, family members, or caregivers of Medicare beneficiaries[1][2][3]"]
  },
  "benefits": {
    "type": "service|advocacy",
    "value": "Free, personalized, unbiased, confidential one-on-one counseling (in-person or phone); education on Medicare Parts A/B/C/D, Medigap, enrollment, appeals, reducing costs; help applying for low-income programs (Medicaid, Medicare Savings Program, Extra Help); group presentations and outreach events; fraud prevention via Senior Medicare Patrol in many areas[1][2][3]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-562-6900 (statewide SHIBA), TTY: 1-360-586-0241[5]", "Website: Washington SHIBA website (via shiphelp.org/ships/washington/)[5]", "In-person or phone through local SHIBA counselors (statewide network)[1][2][5]"],
    "processing_time": "Immediate counseling available upon contact; no formal application processing[1][3]",
    "waitlist": null,
    "forms": ["No specific forms required for counseling; counselors assist with Medicare-related forms during sessions[2]"],
    "documents": ["Medicare card, current insurance details, prescription drug list, income info if seeking low-income program help (optional for initial counseling)[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide in Washington via SHIBA (Statewide Health Insurance Benefits Advisors)[5]",
    "regional_variations": "Delivered through statewide network of local sites and counselors; no specified differences in services, wait times, or providers by region[2][5]",
    "offices_or_providers": ["Statewide SHIBA program with over 2,200 national local sites (Washington-specific locals via phone/website)[2][5]"]
  },
  "official_source": "https://www.shiphelp.org/ships/washington/[5]",
  "gotchas": ["Not a healthcare or financial benefit provider—only free counseling/advocacy, no direct payments or services; counselors are unbiased and cannot sell insurance; contact 3 months before Medicare eligibility for best help; HICAP is California-specific name, Washington uses SHIBA (both under national SHIP)[1][3][4][5]"],
  "data_shape_notes": "no income/asset test; open to all Medicare-related; counseling-only service (not benefits/funds); statewide fixed access via central phone/website; volunteer/staff network varies locally but services uniform"
}

