{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are not specified in current sources for Washington; families must verify current federal poverty guidelines via DOL or local provider[1]. No full table provided in sources.",
    "asset_limits": "No asset limits mentioned in sources[1].",
    "other_requirements": [
      "Unemployed",
      "Priority given to: veterans and qualified spouses, individuals over 65, those with a disability, low literacy skills or limited English proficiency, rural residents, homeless or at risk of homelessness, low employment prospects, or those who failed to find employment after American Job Center services[1]"
    ]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work (average 20 hours per week) at non-profit/public facilities (e.g., schools, hospitals, day-care, senior centers); paid at highest of federal, state, or local minimum wage; on-the-job training in skills like computer/vocational; employment assistance and placement support to unsubsidized jobs[1][4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "In-person or phone: AARP Foundation SCSEP, 3216 Wetmore #203, Everett WA 98201, (425) 366-4457 (Snohomish County)[7]",
      "In-person: WorkSource Whatcom, 101 Prospect Street, Bellingham, WA 98225; email findhelp@worksourcewa.com or visit https://www.worksourcewa.com (Whatcom County)[3]",
      "National: Contact local grantees via DOL SCSEP page (https://www.dol.gov/agencies/eta/seniors) or American Job Centers[1]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": "Not specified; may vary by local provider and funding availability[1]",
    "forms": ["No specific form names/numbers listed; intake via local provider[1]"],
    "documents": ["Not detailed in sources; prepare proof of age, income, unemployment status, and priority factors (e.g., veteran status, disability documentation) based on standard program needs[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via local grantees (e.g., AARP Foundation, WorkSource); no county restrictions noted[1][3][7]",
    "regional_variations": "Administered by different grantees/providers by region (e.g., AARP Foundation in Snohomish/Everett, WorkSource in Whatcom/Bellingham); contact local offices for specifics; wait times/funding may vary by location and grant allocation[3][7]",
    "offices_or_providers": [
      "AARP Foundation SCSEP: 3216 Wetmore #203, Everett WA 98201, (425) 366-4457[7]",
      "WorkSource Whatcom: 101 Prospect Street, Bellingham, WA 98225[3]"
    ]
  },
  "official_source": "https://www.dol.gov/agencies/eta/seniors[1]",
  "gotchas": [
    "Income limit is strictly 125% of federal poverty level; verify current amounts as they update yearly[1]",
    "Priority tiers mean non-priority applicants may face longer waits or limited slots[1]",
    "Program is temporary training bridge to unsubsidized work, not permanent employment or welfare[1][4]",
    "Funded via DOL grants to local non-profits/state agencies (e.g., AARP, WorkSource); availability depends on local funding[1][3][7]",
    "Must be unemployed; not for current workers[1]"
  ],
  "data_shape_notes": "Administered by multiple regional grantees (e.g., AARP Foundation, WorkSource); priority-based enrollment; income at 125% FPL with no asset test specified; 20 hours/week training pay at min wage; no statewide uniform processing times or forms"
}

{
  "name": "Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "In most counties, seniors 60+ are eligible regardless of income. Low-income individuals 60+ qualify in areas like those served by Rural Resources. General NJP services require low-income screening, but seniors often exempt[1][3][7].",
    "asset_limits": "Assets limits may apply for CLEAR*Sr, though specifics not detailed[3].",
    "other_requirements": ["Low-income status (waived for seniors 60+ in most counties)", "Civil legal problems affecting basic needs (e.g., income maintenance, health care, housing, protection against guardianship, consumer issues)", "Washington state resident"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice, consultation, counseling, advocacy, representation, referrals; one-time consultation with attorney in some programs; assistance via phone, electronically; covers income maintenance, health care, housing, protective services, powers of attorney, health care directives, dementia directives[1][3][4][5].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: CLEAR*Sr at 1-888-387-7111 (seniors 60+ regardless of income)", "Phone: General CLEAR at 1-888-201-1014 (Mon-Fri 9:15am-12:15pm)", "Online: Apply via Northwest Justice Project at nwjustice.org", "In-person or referrals: Local NJP offices, partners like Rural Resources, ALTC, Columbia Legal Services", "Mail: Not specified, use online/phone intake"],
    "processing_time": "Immediate advice if possible during call; in-depth interview to assess; high call volume may delay connection[3].",
    "waitlist": "No waitlist mentioned; high call volume may require patience[3].",
    "forms": ["No specific form names/numbers listed; intake via hotline or online application[3][6]."],
    "documents": ["Not explicitly listed; prepare income/asset info if screened, details on legal problem (e.g., documents related to housing, benefits, health care)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via NJP/CLEAR, but delivered through regional offices/partners",
    "regional_variations": "Varies by county: e.g., Rural Resources (rural areas), Snohomish County services, Kitsap ALTC/NJP contract, Benton Franklin Legal Aid, Clallam-Jefferson Pro Bono; different local providers and offices[1][4][5][6].",
    "offices_or_providers": ["Northwest Justice Project (statewide)", "Rural Resources", "ALTC Southeast Washington", "Columbia Legal Services", "County-specific: Snohomish, Kitsap, Benton, Clallam-Jefferson, etc."]
  },
  "official_source": "https://nwjustice.org/clear-hotline",
  "gotchas": ["Income often not a barrier for 60+ but assets may apply; limited to civil/basic needs issues (no criminal/personal injury); high call volume requires patience; one-time consultation in some programs; select counties have unique partners/providers[1][3][7]."],
  "data_shape_notes": "Seniors 60+ often no income test statewide via NJP/CLEAR*Sr, but regional delivery via county partners; services priority on basic needs civil legal issues"
}

{
  "name": "Lifetime Disabled Veteran Pass",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits or asset limits apply. Eligibility is based solely on disability rating and residency, not financial means.",
    "asset_limits": "No asset limits apply. No counts or exemptions specified as they are not part of eligibility.",
    "other_requirements": [
      "Washington State resident (proof required, such as valid WA driver's license, ID card, voter registration, or senior citizen property tax exemption; at least 3 consecutive months residency in some contexts)",
      "Service-connected disability rating of at least 30% from the VA (verified by VA award letter dated within the last 2 years or VA Benefit Summary Letter)",
      "Veteran of US Armed Forces (honorably discharged or equivalent)"
    ]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Lifetime pass providing free day-use access (vehicle parking and individual entry) to Washington State Parks year-round. Accepted at many county parks and recreation sites (e.g., Jefferson County Parks) for free or reduced fees. Does not cover camping, moorage, or expanded amenities unless specified by site.",
    "varies_by": "fixed"
  },
  "application": {
    "methods": [
      "Phone: (360) 902-8844 or Washington Telecommunication Relay Service at (800) 833-6388 to request application",
      "Online: Submit completed Washington State Parks and Recreation Commission Lifetime Disabled Veteran Pass Application by email to passes@parks.wa.gov or fax to 360-586-6440",
      "Mail: Washington State Parks and Recreation Commission (address listed on application form)"
    ],
    "processing_time": "Passes ordered online or by mail delivered in 3-4 weeks after receipt of documentation (similar to federal process; state-specific not detailed)",
    "waitlist": null,
    "forms": [
      "Washington State Parks and Recreation Commission Lifetime Disabled Veteran Pass Application"
    ],
    "documents": [
      "Proof of Washington state residency (e.g., valid WA driver's license or ID card, voter registration card, senior citizen property tax exemption)",
      "VA award letter dated within the last 2 years showing combined service-connected disability rating of 30% or greater, VA Benefit Summary Letter, or letter from military service certifying disability"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to Washington State residents",
    "regional_variations": "Accepted statewide at WA State Parks; some county parks (e.g., Jefferson County) honor it for their passes with no noted differences in eligibility or processing. No regional wait time variations specified.",
    "offices_or_providers": []
  },
  "official_source": "https://wdfw.wa.gov/accessibility/eligibility-requirements-veterans-reduced-fees (referenced in results); primary application via parks.wa.gov",
  "gotchas": [
    "Pass covers day-use fees only (e.g., parking, entry); does not include camping, boat launches, or special events",
    "Must show VA documentation dated within 2 years; older letters may be rejected",
    "Not the same as federal NPS Access Pass or Disabled Veteran Property Tax Exemption—specific to WA State Parks access",
    "Residency proof must be current; at least 3 months in some verifications",
    "No income/asset test, but strictly service-connected disability (not general disability)"
  ],
  "data_shape_notes": "No income or asset tests; fixed eligibility based on 30%+ VA service-connected rating and WA residency; statewide uniform access with acceptance at select county sites; documentation-heavy with recent VA letter requirement"
}

{
  "name": "Seattle Gold Card (Age-Friendly Discount Program)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or asset limits apply. Open to all qualifying by age or disability without financial tests.[1][3][5]",
    "asset_limits": "No asset limits or tests. No information on what counts or exemptions, as none required.[1][5]",
    "other_requirements": ["Must be a resident of Seattle, King County, or Washington state.[1][3][5]", "No proof of residency explicitly required in sources, but residency stated as eligibility.[3]"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Discounts at over 110 participating Seattle-area businesses and nonprofits, including theaters, restaurants, Woodland Park Zoo, Seattle Aquarium, Seattle Art Museum, Museum of Flight, fitness/recreation, food/beverage/grocery, pet adoption/licensing (50% fee reduction at Seattle Animal Shelter), retail, services, arts, entertainment, tourism. Specific discount amounts vary by business; cardholders should confirm acceptance. Directory available online with mapping by zip code.[1][2][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Online: seattle.gov/AgeFriendlyDiscounts or civiform.seattle.gov/programs/gold-card-hsd (10 minutes, 16 languages, card mailed if qualified).[1][2][5][7]", "In-person: Seattle Public Library branches, senior activity centers, community centers, City of Seattle customer service centers, Disability Empowerment Center service centers (Seattle, Redmond, Auburn).[1][4][8]", "Bulk for organizations: Email agefriendly@seattle.gov.[2]", "Phone: (206) 582-5011 (M-F 8am-3:30pm).[5]"],
    "processing_time": "Online applicants receive card in mail within 1-2 weeks.[5]",
    "waitlist": null,
    "forms": ["Online application form at seattle.gov/AgeFriendlyDiscounts or civiform.seattle.gov (no specific form name/number listed).[1][2][7]"],
    "documents": ["No specific documents listed in sources; application described as easy with no mention of required proofs beyond self-attestation of age/residency.[1][2][5]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Seattle, King County, or Washington state residents (administered by City of Seattle, but open beyond city limits).[1][3][5]",
    "regional_variations": "Discounts focused on Seattle-area businesses; available to King County/WA residents including Bellevue and visitors with family. No noted differences in processing or wait times by region; in-person pickup at select centers (e.g., Redmond, Auburn).[1][4]",
    "offices_or_providers": ["Seattle Public Library branches, senior/community centers, customer service centers, Disability Empowerment Center (Seattle, Redmond, Auburn).[1][4][8]"]
  },
  "official_source": "https://www.seattle.gov/agefriendly/about/discount-program",
  "gotchas": ["Not limited to Seattle residents—open to all King County/WA residents 60+ and visitors with family, which surprises some.[1]", "Must confirm with each business if they accept the card, as participation voluntary and list updated regularly.[5][6]", "Separate FLASH Card for 18-59 with disabilities; not the same program.[1][2][5]", "Online application prompts for other Affordable Seattle programs, but Gold Card itself has no income test.[1]", "Physical cards available at libraries/centers without online application.[1][4][8]"],
  "data_shape_notes": "No income or asset test; residency broadly defined across King County/WA; discounts vary by participating businesses only (no fixed dollar/hour value); multiple easy access points including libraries; pairs with FLASH for disabilities."
}
